1	'use client';
2	
3	import React, { useState, useEffect, useRef, useCallback } from 'react';
4	import dynamic from 'next/dynamic';
5	import { Send, Mic, MicOff, Volume2, VolumeX, Loader2, AlertCircle } from 'lucide-react';
6	import ReactMarkdown from 'react-markdown';
7	import remarkGfm from 'remark-gfm';
8	
9	const NeuralBrain = dynamic(() => import('@/components/NeuralBrain'), { ssr: false });
10	
11	// ── types ──────────────────────────────────────────────────────────────────
12	interface Message {
13	  id: string;
14	  role: 'user' | 'assistant';
15	  content: string;
16	}
17	
18	// ── speech recognition types ──────────────────────────────────────────────
19	type SRInstance = {
20	  lang: string;
21	  continuous: boolean;
22	  interimResults: boolean;
23	  onresult: ((e: SREvent) => void) | null;
24	  onerror: ((e: Event) => void) | null;
25	  onend: (() => void) | null;
26	  start(): void;
27	  stop(): void;
28	  abort(): void;
29	};
30	type SREvent = { results: { length: number; [i: number]: { isFinal: boolean; [j: number]: { transcript: string } } } };
31	
32	function getSR(): (new () => SRInstance) | null {
33	  if (typeof window === 'undefined') return null;
34	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
35	  const w = window as any;
36	  return w.SpeechRecognition || w.webkitSpeechRecognition || null;
37	}
38	
39	// ── TTS ────────────────────────────────────────────────────────────────────
40	function browserSpeak(text: string): boolean {
41	  if (typeof window === 'undefined' || !window.speechSynthesis) return false;
42	  window.speechSynthesis.cancel();
43	  const utter = new SpeechSynthesisUtterance(text);
44	  utter.rate = 1.0;
45	  utter.pitch = 1.0;
46	  utter.volume = 1.0;
47	  // Pick a good English voice; fall back to whatever is available
48	  const pickVoice = () => {
49	    const voices = window.speechSynthesis.getVoices();
50	    return (
51	      voices.find(v => v.name.toLowerCase().includes('google') && v.lang.startsWith('en')) ||
52	      voices.find(v => v.lang.startsWith('en')) ||
53	      voices[0]
54	    );
55	  };
56	  const v = pickVoice();
57	  if (v) utter.voice = v;
58	  window.speechSynthesis.speak(utter);
59	  return true;
60	}
61	
62	// ── stream parser ──────────────────────────────────────────────────────────
63	// Handles both Vercel AI SDK (0:"chunk") and plain-text (Firebase / Gemini) streams
64	function parseChunk(chunk: string): string {
65	  let out = '';
66	  for (const line of chunk.split('\n')) {
67	    if (line.startsWith('0:')) {
68	      try {
69	        const delta = JSON.parse(line.slice(2));
70	        if (typeof delta === 'string') out += delta;
71	      } catch { /* skip malformed */ }
72	    } else if (
73	      line.trim() &&
74	      !line.startsWith('e:') &&
75	      !line.startsWith('d:') &&
76	      !line.startsWith('data:') &&
77	      !line.startsWith('f:') &&
78	      !line.startsWith('8:') &&
79	      !line.startsWith('2:')
80	    ) {
81	      out += line;
82	    }
83	  }
84	  return out;
85	}
86	
87	// ── component ──────────────────────────────────────────────────────────────
88	export default function ChatPage() {
89	  const [messages, setMessages]     = useState<Message[]>([]);
90	  const [input, setInput]           = useState('');
91	  const [isStreaming, setIsStreaming] = useState(false);
92	  const [isListening, setIsListening] = useState(false);
93	  const [ttsEnabled, setTtsEnabled]  = useState(true);
94	  const [transcript, setTranscript]  = useState('');
95	  const [error, setError]            = useState<string | null>(null);
96	
97	  const messagesEndRef = useRef<HTMLDivElement>(null);
98	  const recognitionRef = useRef<SRInstance | null>(null);
99	  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
100	  const mediaStreamRef = useRef<MediaStream | null>(null);
101	  const audioChunksRef = useRef<Blob[]>([]);
102	  const audioRef = useRef<HTMLAudioElement | null>(null);
103	  const abortRef       = useRef<AbortController | null>(null);
104	  const textareaRef    = useRef<HTMLTextAreaElement>(null);
105	
106	  // Load TTS voices eagerly (Chrome lazy-loads them)
107	  useEffect(() => {
108	    const load = () => window.speechSynthesis?.getVoices();
109	    load();
110	    window.speechSynthesis?.addEventListener?.('voiceschanged', load);
111	    return () => window.speechSynthesis?.removeEventListener?.('voiceschanged', load);
112	  }, []);
113	
114	  useEffect(() => {
115	    return () => {
116	      recognitionRef.current?.abort();
117	      mediaRecorderRef.current?.stop();
118	      mediaStreamRef.current?.getTracks().forEach(track => track.stop());
119	      audioRef.current?.pause();
120	      if (typeof window !== 'undefined') {
121	        window.speechSynthesis?.cancel();
122	      }
123	    };
124	  }, []);
125	
126	  // Auto-scroll on new messages
127	  useEffect(() => {
128	    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
129	  }, [messages]);
130	
131	  // Auto-resize textarea
132	  useEffect(() => {
133	    const ta = textareaRef.current;
134	    if (!ta) return;
135	    ta.style.height = 'auto';
136	    ta.style.height = Math.min(ta.scrollHeight, 140) + 'px';
137	  }, [input]);
138	
139	  const transcribeAudio = useCallback(async (audioBlob: Blob) => {
140	    const formData = new FormData();
141	    formData.append('audio', audioBlob, `voice-input-${Date.now()}.webm`);
142	
143	    const res = await fetch('/api/stt', {
144	      method: 'POST',
145	      body: formData,
146	    });
147	
148	    if (!res.ok) {
149	      const body = await res.text().catch(() => '');
150	      throw new Error(`Speech recognition failed: ${body.slice(0, 200)}`);
151	    }
152	
153	    const data = await res.json() as { transcription?: string };
154	    const transcription = data.transcription?.trim();
155	    if (!transcription) {
156	      throw new Error('No transcription returned from speech service');
157	    }
158	
159	    return transcription;
160	  }, []);
161	
162	  const speakResponse = useCallback(async (text: string) => {
163	    if (!ttsEnabled || !text) return;
164	
165	    audioRef.current?.pause();
166	    audioRef.current = null;
167	
168	    if (browserSpeak(text)) return;
169	
170	    const res = await fetch('/api/tts', {
171	      method: 'POST',
172	      headers: { 'Content-Type': 'application/json' },
173	      body: JSON.stringify({ text }),
174	    });
175	
176	    if (!res.ok) {
177	      const body = await res.text().catch(() => '');
178	      throw new Error(`Speech playback failed: ${body.slice(0, 200)}`);
179	    }
180	
181	    const audioBlob = await res.blob();
182	    const audioUrl = URL.createObjectURL(audioBlob);
183	    const audio = new Audio(audioUrl);
184	    audioRef.current = audio;
185	    audio.onended = () => URL.revokeObjectURL(audioUrl);
186	    audio.onerror = () => URL.revokeObjectURL(audioUrl);
187	    await audio.play();
188	  }, [ttsEnabled]);
189	
190	  // ── send ─────────────────────────────────────────────────────────────────
191	  const sendMessage = useCallback(async (text: string) => {
192	    const trimmed = text.trim();
193	    if (!trimmed || isStreaming) return;
194	
195	    setError(null);
196	    setInput('');
197	    setTranscript('');
198	
199	    const userMsg: Message = { id: `u-${Date.now()}`, role: 'user', content: trimmed };
200	    const history = [...messages, userMsg];
201	    setMessages(history);
202	    setIsStreaming(true);
203	
204	    const assistantId = `a-${Date.now()}`;
205	    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', content: '' }]);
206	
207	    try {
208	      abortRef.current?.abort();
209	      const abort = new AbortController();
210	      abortRef.current = abort;
211	
212	      const res = await fetch('/api/chat/stream', {
213	        method: 'POST',
214	        headers: { 'Content-Type': 'application/json' },
215	        body: JSON.stringify({ messages: history.map(m => ({ role: m.role, content: m.content })) }),
216	        signal: abort.signal,
217	      });
218	
219	      if (!res.ok) {
220	        const body = await res.text().catch(() => '');
221	        throw new Error(`HTTP ${res.status}: ${body.slice(0, 120)}`);
222	      }
223	
224	      const reader = res.body?.getReader();
225	      const decoder = new TextDecoder();
226	      let accumulated = '';
227	
228	      if (reader) {
229	        while (true) {
230	          const { done, value } = await reader.read();
231	          if (done) break;
232	          const delta = parseChunk(decoder.decode(value, { stream: true }));
233	          if (delta) {
234	            accumulated += delta;
235	            setMessages(prev =>
236	              prev.map(m => m.id === assistantId ? { ...m, content: accumulated } : m)
237	            );
238	          }
239	        }
240	      }
241	
242	      // TTS — speak the complete response
243	      if (ttsEnabled && accumulated) {
244	        // Small delay so the UI settles first
245	        setTimeout(() => {
246	          void speakResponse(accumulated).catch((err: Error) => {
247	            setError(`Voice playback error: ${err.message}`);
248	          });
249	        }, 80);
250	      }
251	    } catch (err) {
252	      if ((err as Error).name !== 'AbortError') {
253	        const msg = (err as Error).message;
254	        setError(msg.includes('quota') ? 'AI quota exhausted — check provider config' : `Neural link error: ${msg}`);
255	        setMessages(prev => prev.filter(m => m.id !== assistantId));
256	      }
257	    } finally {
258	      setIsStreaming(false);
259	      abortRef.current = null;
260	    }
261	  // eslint-disable-next-line react-hooks/exhaustive-deps
262	  }, [messages, isStreaming, speakResponse]);
263	
264	  // ── STT ──────────────────────────────────────────────────────────────────
265	  const startListening = useCallback(async () => {
266	    audioRef.current?.pause();
267	    audioRef.current = null;
268	    window.speechSynthesis?.cancel();
269	
270	    const SR = getSR();
271	    if (!SR) {
272	      try {
273	        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
274	        mediaStreamRef.current = stream;
275	        audioChunksRef.current = [];
276	
277	        const preferredMimeType = MediaRecorder.isTypeSupported('audio/webm;codecs=opus')
278	          ? 'audio/webm;codecs=opus'
279	          : 'audio/webm';
280	        const recorder = new MediaRecorder(stream, { mimeType: preferredMimeType });
281	        mediaRecorderRef.current = recorder;
282	
283	        recorder.ondataavailable = (event) => {
284	          if (event.data.size > 0) {
285	            audioChunksRef.current.push(event.data);
286	          }
287	        };
288	
289	        recorder.onstop = async () => {
290	          mediaStreamRef.current?.getTracks().forEach(track => track.stop());
291	          mediaStreamRef.current = null;
292	          mediaRecorderRef.current = null;
293	
294	          const audioBlob = new Blob(audioChunksRef.current, { type: preferredMimeType });
295	          audioChunksRef.current = [];
296	          if (!audioBlob.size) {
297	            setTranscript('');
298	            return;
299	          }
300	
301	          setTranscript('Transcribing...');
302	          try {
303	            const finalTranscript = await transcribeAudio(audioBlob);
304	            setTranscript(finalTranscript);
305	            await sendMessage(finalTranscript);
306	          } catch (err) {
307	            setError((err as Error).message);
308	          }
309	        };
310	
311	        recorder.start();
312	        setTranscript('Listening...');
313	        setIsListening(true);
314	        setError(null);
315	      } catch (err) {
316	        setError(`Mic error: ${(err as Error).message}`);
317	      }
318	      return;
319	    }
320	
321	    const rec = new SR();
322	    rec.lang = 'en-US';
323	    rec.continuous = false;
324	    rec.interimResults = true;
325	
326	    rec.onresult = (e: SREvent) => {
327	      let interim = '';
328	      let final = '';
329	      for (let i = 0; i < e.results.length; i++) {
330	        const r = e.results[i];
331	        if (r.isFinal) final += r[0].transcript;
332	        else interim += r[0].transcript;
333	      }
334	      setTranscript(final || interim);
335	      if (final) {
336	        rec.stop();
337	        setIsListening(false);
338	        sendMessage(final);
339	      }
340	    };
341	
342	    rec.onerror = (e: Event) => {
343	      const code = (e as unknown as { error: string }).error;
344	      setIsListening(false);
345	      if (code !== 'aborted') setError(`Mic error: ${code}`);
346	    };
347	
348	    rec.onend = () => setIsListening(false);
349	
350	    rec.start();
351	    recognitionRef.current = rec;
352	    setIsListening(true);
353	    setError(null);
354	  }, [sendMessage, transcribeAudio]);
355	
356	  const stopListening = useCallback(() => {
357	    if (recognitionRef.current) {
358	      recognitionRef.current.abort();
359	      recognitionRef.current = null;
360	    }
361	
362	    if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
363	      mediaRecorderRef.current.stop();
364	      setTranscript('Transcribing...');
365	    }
366	
367	    setIsListening(false);
368	  }, []);
369	
370	  const toggleMic = () => {
371	    if (isListening) stopListening();
372	    else startListening();
373	  };
374	
375	  const toggleTTS = () => {
376	    if (ttsEnabled) {
377	      window.speechSynthesis?.cancel();
378	      audioRef.current?.pause();
379	      audioRef.current = null;
380	    }
381	    setTtsEnabled(s => !s);
382	  };
383	
384	  const handleKeyDown = (e: React.KeyboardEvent) => {
385	    if (e.key === 'Enter' && !e.shiftKey) {
386	      e.preventDefault();
387	      sendMessage(input);
388	    }
389	  };
390	
391	  const isEmpty = messages.length === 0;
392	  const lastMsg = messages[messages.length - 1];
393	
394	  return (
395	    <div className="omega-root">
396	      {/* Neural canvas background */}
397	      <div className="omega-bg">
398	        <NeuralBrain isActive={isStreaming || isListening} />
399	      </div>
400	
401	      {/* ── Header ── */}
402	      <header className="omega-header">
403	        <div className="omega-logo">
404	          <span className="omega-symbol">Ω</span>
405	        </div>
406	        <span className="omega-brand">Chyren</span>
407	
408	        <div className="omega-header-status">
409	          <span className={`omega-status-dot ${(isStreaming || isListening) ? 'omega-status-active' : ''}`} />
410	          <span className="omega-status-label">
411	            {isStreaming ? 'PROCESSING' : isListening ? 'LISTENING' : 'SOVEREIGN'}
412	          </span>
413	        </div>
414	
415	        <div className="omega-header-actions">
416	          <button onClick={toggleTTS} className="omega-icon-btn" title={ttsEnabled ? 'Mute Chyren' : 'Enable voice'}>
417	            {ttsEnabled ? <Volume2 size={15} /> : <VolumeX size={15} />}
418	          </button>
419	        </div>
420	      </header>
421	
422	      {/* ── Main ── */}
423	      <main className="omega-main">
424	        {isEmpty ? (
425	          <div className="omega-idle">
426	            <div className="omega-idle-title">
427	              <span className="omega-idle-omega">Ω</span>
428	              <span className="omega-idle-name">Chyren</span>
429	            </div>
430	            <p className="omega-idle-sub">SOVEREIGN INTELLIGENCE ORCHESTRATOR</p>
431	            <p className="omega-idle-desc">
432	              High-integrity cognitive processing and neural telemetry. Speak or type to initiate a session.
433	            </p>
434	
435	            {/* Voice orb */}
436	            <button
437	              className={`omega-orb ${isListening ? 'omega-orb-active' : ''}`}
438	              onClick={toggleMic}
439	              disabled={isStreaming}
440	              aria-label="Voice input"
441	            >
442	              <div className="omega-orb-ring omega-orb-ring-1" />
443	              <div className="omega-orb-ring omega-orb-ring-2" />
444	              <div className="omega-orb-ring omega-orb-ring-3" />
445	              <div className="omega-orb-core">
446	                {isListening ? <MicOff size={26} /> : <Mic size={26} />}
447	              </div>
448	            </button>
449	
450	            <p className="omega-orb-label">
451	              {isListening ? 'LISTENING — SPEAK NOW' : 'INITIALIZE NEURAL INTENT'}
452	            </p>
453	
454	            {transcript && <p className="omega-transcript">{transcript}</p>}
455	          </div>
456	        ) : (
457	          <div className="omega-messages">
458	            {messages.map(msg => (
459	              <div key={msg.id} className={`omega-msg omega-msg-${msg.role}`}>
460	                <div className="omega-msg-label">
461	                  {msg.role === 'user' ? '▸ OPERATOR' : 'Ω CHYREN'}
462	                </div>
463	                <div className="omega-msg-content">
464	                  {msg.role === 'assistant' ? (
465	                    <>
466	                      <ReactMarkdown remarkPlugins={[remarkGfm]}>{msg.content}</ReactMarkdown>
467	                      {isStreaming && msg === lastMsg && <span className="omega-cursor" />}
468	                    </>
469	                  ) : (
470	                    <p>{msg.content}</p>
471	                  )}
472	                </div>
473	              </div>
474	            ))}
475	            {/* Transcript bar while listening mid-conversation */}
476	            {isListening && transcript && (
477	              <p className="omega-transcript-bar">{transcript}</p>
478	            )}
479	            <div ref={messagesEndRef} />
480	          </div>
481	        )}
482	
483	        {error && (
484	          <div className="omega-error">
485	            <AlertCircle size={13} />
486	            <span>{error}</span>
487	            <button className="omega-error-dismiss" onClick={() => setError(null)}>✕</button>
488	          </div>
489	        )}
490	      </main>
491	
492	      {/* ── Footer / input ── */}
493	      <footer className="omega-footer">
494	        <div className="omega-input-wrap">
495	          <button
496	            className={`omega-voice-btn ${isListening ? 'omega-voice-btn-active' : ''}`}
497	            onClick={toggleMic}
498	            disabled={isStreaming}
499	            aria-label={isListening ? 'Stop listening' : 'Start voice input'}
500	          >
501	            {isListening ? <MicOff size={17} /> : <Mic size={17} />}
502	          </button>
503	
504	          <textarea
505	            ref={textareaRef}
506	            className="omega-textarea"
507	            value={isListening ? (transcript || '') : input}
508	            onChange={e => setInput(e.target.value)}
509	            onKeyDown={handleKeyDown}
510	            placeholder="▸  transmit cognitive intent..."
511	            rows={1}
512	            disabled={isStreaming || isListening}
513	          />
514	
515	          <button
516	            className="omega-send-btn"
517	            onClick={() => sendMessage(input)}
518	            disabled={isStreaming || isListening || !input.trim()}
519	            aria-label="Send"
520	          >
521	            {isStreaming ? <Loader2 size={17} className="omega-spin" /> : <Send size={17} />}
522	          </button>
523	        </div>
524	
525	        <div className="omega-footer-meta">
526	          <span className="omega-footer-label">NEURAL LINK</span>
527	          <span className={`omega-footer-dot ${isStreaming ? 'omega-footer-dot-active' : ''}`} />
528	          <span className="omega-footer-label">{isStreaming ? 'ACTIVE' : 'STANDBY'}</span>
529	        </div>
530	      </footer>
531	    </div>
532	  );
533	}
